# Classes
class Style(Enum):
    """
    Enum for the style of the plot
    """
    POSTERIOR = "posterior"
    PRIOR = "prior"

class Mode(Enum):
    """
    Enum for the mode of the plot
    """
    NS = "NS"
    TWINS = "twins"
    BOTH = "both"

class GridType(Enum):
    """
    Enum for grid style
    """
    LINEAR = "linear"
    LOGARITHMIC = "logarithmic"

class PlotStyle(Enum):
    """
    Enum for the plot style
    """
    BINS = "bins"
    LINES = "lines"
    SCATTER = "scatter"

class EoSFamily(Enum):
    """
    Family of the EoS; 0<n1<3 ns, 0<dn<3 ns > class 1;  3<n1<20 ns, 0<dn<3 ns > class 2
    """
    FAM_1 = "Fam 1"
    FAM_2 = "Fam 2"

class Param(Enum):
    """
    Calculate n1 or dn credible intervals
    """
    n1 = "n1"
    dn = "dn"

# Parse arguments
def parse_args():
    """
    Parse command line arguments.
    """
    parser = argparse.ArgumentParser()

    # Set mode {"twins" / "NS" / "both"}
    parser.add_argument("--mode",
                        type=str, 
                        choices=[m.value for m in Mode], 
                        default=Mode.TWINS.value)
    
    # Set style {"prior" / "posterior"}
    parser.add_argument("--style",
                        type=str, 
                        choices=[s.value for s in Style], 
                        default=Style.POSTERIOR.value)
    
    # Set plot style {"bins" / "lines"}
    parser.add_argument("--plotstyle", 
                        type=str, 
                        choices=[s.value for s in PlotStyle], 
                        default=PlotStyle.BINS.value)
    
    # Set number of EOS to plot, default 200
    parser.add_argument("--NEOS",
                        type=int, 
                        default=200, 
                        help="Number of EOS to plot")
    

    return parser.parse_args()


